class Solution {
    public static long solve(long[] nums) {
        int n = nums.length;
        if (n <= 1) {
            return 0;
        }

        // aPrev stores A_{i-1}, the required total increment for nums[i-1].
        // We assume A_0 = 0 initially.
        long aPrev = 0; 
        long totalCost = 0;

        // Iterate from i=1 up to n-1 to calculate A_i and the corresponding cost increase C_i.
        for (int i = 1; i < n; i++) {
            // D = nums[i-1] - nums[i]. This is the minimum required difference A_i - A_{i-1}.
            long D = nums[i-1] - nums[i];

            // A_required is the minimum possible value for A_i based on A_{i-1} and the constraint D.
            long aRequired = aPrev + D;

            // A_i must be non-negative.
            long aCurrent = Math.max(0L, aRequired);

            // The cost incurred at this step is max(0, A_i - A_{i-1}).
            long costIncrease = Math.max(0L, aCurrent - aPrev);

            totalCost += costIncrease;

            // Update A_prev for the next iteration
            aPrev = aCurrent;
        }

        return totalCost;
    }
}
