public static long solve(long[] nums) {
    if (nums == null || nums.length <= 1) {
        return 0;
    }

    long totalSum = 0;
    int n = nums.length;

    // We need to ensure A[i] <= A[i+1] for all i.
    // This requires C[i+1] - C[i] >= max(0, nums[i] - nums[i+1]),
    // where C[i] is the total increase applied to nums[i].
    // The minimum total cost is the sum of all required positive increases (R_i).
    for (int i = 0; i < n - 1; i++) {
        long difference = nums[i] - nums[i+1];
        if (difference > 0) {
            totalSum += difference;
        }
    }

    return totalSum;
}

