import java.lang.Math;

public static long solve(long[] nums) {
    int n = nums.length;
    if (n <= 1) {
        return 0;
    }

    // Step 1: Calculate the minimal required additive profile A.
    // A[i] represents the minimum total amount that must be added to nums[i]
    // to satisfy all non-decreasing constraints up to index i.
    long[] A = new long[n];

    // We assume A[0] = 0 to minimize the total sum of x's.
    A[0] = 0;

    for (int i = 1; i < n; i++) {
        // We require nums[i-1] + A[i-1] <= nums[i] + A[i]
        // This means A[i] - A[i-1] >= nums[i-1] - nums[i].
        long required_diff = nums[i - 1] - nums[i];

        // Calculate the minimum value for A[i] based on A[i-1] and the constraint.
        long candidate_Ai = A[i - 1] + required_diff;

        // A[i] must also be non-negative.
        A[i] = Math.max(0, candidate_Ai);
    }

    // Step 2: Calculate the minimum total sum of x's.
    // The minimum total sum of range increments required to achieve profile A 
    // (starting from A[-1]=0) is the sum of all positive differences A[i+1] - A[i].
    long total_sum_x = 0;

    for (int i = 0; i < n - 1; i++) {
        long difference = A[i + 1] - A[i];
        if (difference > 0) {
            total_sum_x += difference;
        }
    }

    return total_sum_x;
}
